parameters.functionCode:
/*
Expected body examples:
{
  "userId": "user_123",
  "method": "can" | "pickle" | "freeze" | "dehydrate" | "ferment",
  "productName": "Tomato Sauce",
  "items": [
    { "variety": "Roma", "netWeight": 16, "unit": "oz", "jarSize": "pint", "count": 7, "ingredients": ["Tomato","Salt","Basil"] }
  ],
  "shelfLifeDays": 365,              // optional global override
  "templateId": "jar_label_v1",     // optional
  "makeTicket": true                  // default true
}
*/
const body = items[0]?.json || {};
const apiBase = $env.SUKA_API_BASE || 'http://localhost:4000';

function normArr(x){ return Array.isArray(x) ? x : (x ? [x] : []); }
function iso(x){ try { return x ? new Date(x).toISOString() : new Date().toISOString(); } catch { return new Date().toISOString(); } }
function addDays(dateISO, days){ const d = new Date(dateISO); d.setDate(d.getDate() + Number(days || 0)); return d.toISOString().slice(0,10); }
function today(){ return new Date().toISOString().slice(0,10); }
function pad(n){ return String(n).padStart(2,'0'); }
function batchCode(method){ const d = new Date(); const y=d.getFullYear(); const m=pad(d.getMonth()+1); const dd=pad(d.getDate()); const tag=String(method||'BATCH').toUpperCase().replace(/[^A-Z0-9]/g,''); const rand=String(Math.floor(Math.random()*1000)).padStart(3,'0'); return `${tag}-${y}${m}${dd}-${rand}`; }

const DEFAULT_SHELF = { can: 365, pickle: 365, freeze: 180, dehydrate: 365, ferment: 180 };

const userId = body.userId || null;
const method = String(body.method || 'freeze').toLowerCase();
const productName = body.productName || null; // optional; we can build one
const itemsIn = normArr(body.items).map(x => ({
  variety: x.variety || null,
  netWeight: (x.netWeight != null) ? Number(x.netWeight) : null,
  unit: x.unit || null,
  jarSize: x.jarSize || null,
  count: Math.max(1, Number(x.count || 1)),
  ingredients: normArr(x.ingredients)
}));

// derive humane product name if not provided
function defaultName(m, v){
  if (productName) return productName;
  const base = { can: 'Canned', pickle: 'Pickled', freeze: 'Frozen', dehydrate: 'Dehydrated', ferment: 'Fermented' }[m] || 'Preserved';
  const noun = v ? `${v}` : 'Produce';
  return `${base} ${noun}`;
}

const packedOn = today();
const shelfLifeDays = Number(body.shelfLifeDays || DEFAULT_SHELF[method] || 180);
const bestBy = addDays(`${packedOn}T00:00:00.000Z`, shelfLifeDays);
const code = batchCode(method);

// Expand into label items (one per physical unit)
const labelItems = [];
for (const it of itemsIn) {
  const per = Math.max(1, it.count || 1);
  for (let i=0; i<per; i++) {
    labelItems.push({
      productName: defaultName(method, it.variety),
      batchCode: code,
      packedOn,
      bestBy,
      method,
      variety: it.variety || undefined,
      netWeight: it.netWeight || undefined,
      unit: it.unit || undefined,
      jarSize: it.jarSize || undefined,
      ingredients: it.ingredients.length ? it.ingredients : undefined
    });
  }
}

// Ticket suggestion
const makeTicket = (body.makeTicket === undefined) ? true : !!body.makeTicket;
const totalUnits = labelItems.length;
const ticket = !makeTicket ? null : {
  title: `Preserve: ${defaultName(method, itemsIn[0]?.variety)} (${totalUnits} unit${totalUnits===1?'':'s'})`,
  category: 'preservation',
  labels: ['preservation', method, packedOn],
  priority: 2,
  due: iso(),
  meta: { method, batchCode: code, bestBy, items: itemsIn },
  userId
};

return [{ json: { apiBase, userId, method, productName: productName || defaultName(method, itemsIn[0]?.variety), templateId: body.templateId || null, labelItems, ticket } }];

const printed = ($items('HTTP: Print Labels', 0, 0)?.length) ? true : false;
const ticketMade = ($items('HTTP: Create Preservation Ticket', 0, 0)?.length) ? true : false;
const ctx = items[0].json;
return [{ json: { ok: true, productName: ctx.productName, method: ctx.method, labelsRequested: (ctx.labelItems||[]).length, printed, ticketMade } }];
